-- Spousal Support — Permanent
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_084', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 4320-4326 (Permanent Spousal Support)', 'FC §§ 4320-4326', 'Spousal Support — Permanent — Marital Standard of Living and 14 Factors', 'Permanent (long-term) spousal support is determined by the court after consideration of 14 statutory factors under FC § 4320. The marital standard of living is the benchmark, not a guaranteed entitlement. Factors include: extent to which earning capacity maintains the marital standard of living, marketable skills, job market, time/expense for education, needs, obligations, assets, duration of marriage, ability of supported party to engage in gainful employment without undue interference with dependent children, age and health, documented domestic violence, tax consequences, balance of hardships, goal of self-support within reasonable time, and criminal conviction of abusive spouse. For marriages of long duration (10+ years), court retains indefinite jurisdiction unless otherwise agreed. Court must make findings if departing from marital standard of living.', '["14 statutory factors in FC § 4320 — court must consider all","Marital standard of living is benchmark (§ 4320(a))","Earning capacity of each party — ability to maintain standard (§ 4320(a))","Marketable skills, job market, education needed (§ 4320(a)(1)-(3))","Supporting spouse contribution to supported spouse career/education (§ 4320(b))","Ability to pay — supporting spouse earning capacity and assets (§ 4320(c))","Needs of each party based on marital standard of living (§ 4320(d))","Obligations and assets including separate property (§ 4320(e))","Duration of marriage — long duration (10+ years) retains jurisdiction indefinitely (§ 4336)","Ability of supported party to work without undue interference with dependent children (§ 4320(g))","Age and health of parties (§ 4320(h))","Documented history of domestic violence (§ 4320(i))","Tax consequences to each party (§ 4320(j))","Balance of hardships (§ 4320(k))","Goal of self-support within reasonable time — half duration of marriage as guideline (§ 4320(l))","Criminal conviction of abusive spouse: rebuttable presumption against support to abuser (§ 4320(m), § 4324.5)","Court may modify or terminate upon material change of circumstances","Gavron warning: supported party expected to become self-supporting (Marriage of Gavron)"]', '[{"section":"4320","description":"Factors for permanent spousal support — all 14 enumerated"},{"section":"4320(a)","description":"Marital standard of living — earning capacity to maintain"},{"section":"4320(d)","description":"Needs based on marital standard of living"},{"section":"4320(g)","description":"Employment vs. care of dependent children"},{"section":"4320(h)","description":"Age and health of parties"},{"section":"4320(i)","description":"Documented history of domestic violence"},{"section":"4320(l)","description":"Goal of self-support within reasonable time"},{"section":"4320(m)","description":"Criminal conviction of abusive spouse"},{"section":"4324.5","description":"Rebuttable presumption against support to convicted DV perpetrator"},{"section":"4326","description":"Court may not base award on gender"},{"section":"4336","description":"Long-duration marriage — indefinite jurisdiction"}]', '["spousal_support_order","income_and_expense_declaration","FL-150","modification_motion","request_for_order","spousal_support_brief","Gavron_warning","vocational_evaluation","Marriage_of_Gavron"]', '["family-law-custody-audit"]', 'Superior Court — Family Division', 1, 1, datetime('now'), datetime('now'));

-- Domestic Violence Restraining Order
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_085', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 6300-6389 (Domestic Violence Prevention Act — DVPA)', 'FC §§ 6300-6389 / DVPA', 'Domestic Violence Restraining Order — DVPA Protective Orders', 'The DVPA authorizes restraining orders to prevent domestic violence between persons in specified relationships: spouse, former spouse, cohabitant, person with whom petitioner has a child, dating relationship, or persons related by consanguinity or affinity within second degree. Abuse includes: intentionally or recklessly causing or attempting to cause bodily injury, sexual assault, placing in reasonable apprehension of imminent serious bodily injury, and engaging in behavior that has been or could be enjoined under § 6320 (molesting, attacking, striking, stalking, threatening, harassing, telephoning, destroying property, disturbing the peace). Temporary Restraining Order (TRO) may be issued ex parte on showing of reasonable proof of past abuse. Hearing within 21 days (extendable to 25) for permanent order. Restraining order may include: stay-away, move-out, custody/visitation, property control, restitution, counseling, and firearm relinquishment. Duration: up to 5 years, renewable. CLETS entry required.', '["Abuse defined: bodily injury, sexual assault, apprehension of injury, enumerated behaviors (§ 6203)","Domestic violence: abuse perpetrated against specified persons (§ 6211)","Protected relationships: spouse, former spouse, cohabitant, parent of child, dating, related within 2nd degree (§ 6211)","Ex parte TRO: may be granted on reasonable proof of past abuse (§ 6300)","Hearing within 21 days of TRO issuance (extendable to 25 days) (§ 6340)","Restraining order may include: personal conduct, stay-away, residence exclusion (§ 6320-6322)","Custody and visitation orders within DVRO (§ 6323)","Property control: exclusive use of shared property (§ 6324)","Firearm relinquishment required within 24 hours (§ 6389)","Restitution for losses caused by abuse (§ 6342)","Batterer intervention program may be ordered (§ 6343)","Duration: up to 5 years; renewable without showing of further abuse (§ 6345)","Permanent restraining order: after hearing with notice (§ 6340)","Violation: criminal offense under PC § 273.6 — misdemeanor or felony","CLETS entry required — law enforcement database (§ 6380)","Mutual restraining orders prohibited unless both parties file and court makes detailed findings (§ 6305)","No filing fee for DVRO petition (§ 6222)"]', '[{"section":"6203","description":"Definition of abuse — bodily injury, sexual assault, apprehension, enumerated conduct"},{"section":"6211","description":"Domestic violence — abuse against protected persons"},{"section":"6300","description":"Ex parte TRO — issuance on reasonable proof of past abuse"},{"section":"6305","description":"Mutual restraining orders — prohibited except with detailed findings"},{"section":"6320","description":"Personal conduct orders — molesting, striking, stalking, harassing"},{"section":"6321","description":"Residence exclusion order — move-out"},{"section":"6322","description":"Stay-away order — distance from person, home, workplace"},{"section":"6323","description":"Custody and visitation orders within DVRO"},{"section":"6340","description":"Hearing within 21 days — permanent order after noticed hearing"},{"section":"6345","description":"Duration — up to 5 years, renewable"},{"section":"6380","description":"CLETS entry — law enforcement database entry required"},{"section":"6389","description":"Firearm relinquishment — within 24 hours of order"}]', '["DV-100","DV-109","DV-110","DV-130","DVRO_petition","temporary_restraining_order","proof_of_service","CLETS_entry","firearm_relinquishment_receipt","batterer_intervention_order","custody_order","FL-300"]', '["family-law-custody-audit"]', 'Superior Court — Family Division / Law Enforcement (CLETS)', 1, 1, datetime('now'), datetime('now'));

-- Civil Harassment Restraining Order
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_086', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Code Civ. Proc. § 527.6 (Civil Harassment Restraining Order)', 'CCP § 527.6', 'Civil Harassment Restraining Order — Non-Domestic Violence Protective Orders', 'Allows a person who has suffered harassment to obtain a temporary restraining order and injunction prohibiting harassment. Harassment is defined as unlawful violence, a credible threat of violence, or a knowing and willful course of conduct directed at a specific person that seriously alarms, annoys, or harasses the person and serves no legitimate purpose (the course of conduct must be such as would cause a reasonable person to suffer substantial emotional distress). Does not apply to persons in domestic relationships (those persons use DVPA). Petitioner must show by clear and convincing evidence at hearing. TRO may be issued ex parte. Hearing within 21-25 days. Injunction may last up to 5 years, renewable. No filing fee for victims of violence or stalking. CLETS entry required for granted orders.', '["Harassment: unlawful violence, credible threat of violence, or knowing/willful course of conduct (§ 527.6(b))","Course of conduct: pattern of conduct composed of a series of acts over a period of time","Must seriously alarm, annoy, or harass with no legitimate purpose","Standard: would cause reasonable person to suffer substantial emotional distress","Does NOT apply to domestic relationships — use DVPA (FC § 6300+)","Does NOT apply to workplace harassment — use CCP § 527.8 (employer petition)","TRO: ex parte, on showing of reasonable proof of harassment","Hearing within 21 days (extendable to 25 days)","Burden: clear and convincing evidence at hearing","Injunction: personal conduct, stay-away orders","Duration: up to 5 years; renewable upon petition (§ 527.6(j))","CLETS entry required for granted injunctions","Violation: contempt of court (PC § 166) and/or criminal violation (PC § 273.6)","Attorney fees may be awarded (§ 527.6(s))","Constitutionally protected speech: orders must not infringe First Amendment","Anti-SLAPP (CCP § 425.16) may apply to civil harassment petitions"]', '[{"section":"527.6(a)","description":"Person who has suffered harassment may seek TRO and injunction"},{"section":"527.6(b)(1)","description":"Harassment defined — violence, threat, or course of conduct"},{"section":"527.6(b)(2)","description":"Unlawful violence — assault, battery, stalking"},{"section":"527.6(b)(3)","description":"Credible threat of violence — fear of safety"},{"section":"527.6(c)","description":"TRO — ex parte issuance upon reasonable proof"},{"section":"527.6(d)","description":"Hearing within 21 days — may extend to 25"},{"section":"527.6(i)","description":"Clear and convincing evidence standard at hearing"},{"section":"527.6(j)","description":"Duration — up to 5 years, renewable"},{"section":"527.6(k)","description":"CLETS entry required"},{"section":"527.6(s)","description":"Attorney fees — court may award to prevailing party"}]', '["CH-100","CH-109","CH-110","CH-130","civil_harassment_petition","temporary_restraining_order","proof_of_service","CLETS_entry","declaration","attorney_fee_motion"]', '["family-law-custody-audit"]', 'Superior Court — Civil Division', 1, 1, datetime('now'), datetime('now'));

-- Move-Away Orders
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_087', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 7501 + Marriage of Burgess (1996) + Marriage of LaMusga (2004) (Move-Away Orders)', 'FC § 7501 / Burgess / LaMusga', 'Move-Away Orders — Custodial Parent Relocation with Minor Children', 'A parent with sole physical custody has a presumptive right to change the residence of the child (FC § 7501). The noncustodial parent bears the burden to show that the proposed move would cause detriment to the child warranting a change in custody (Marriage of Burgess). For joint physical custody, there is no presumptive right — the court applies a best interest analysis (Marriage of LaMusga). LaMusga factors: (1) children''s interest in stability and continuity, (2) distance of move, (3) age of children, (4) children''s relationship with both parents, (5) relationship between parents and ability to communicate and cooperate, (6) wishes of children if of sufficient age, (7) reasons for proposed move, (8) extent to which parents currently share custody. Court must not use the move itself as a change of circumstances to change custody from the moving parent. Roe v. Roe: good faith requirement — move must not be primarily to frustrate the other parent''s contact.', '["FC § 7501: parent entitled to change residence unless court order restricts","Sole custody: presumptive right to relocate (Marriage of Burgess)","Noncustodial parent burden: show detriment warranting custody change (Burgess)","Joint physical custody: no presumptive right — best interest analysis (LaMusga)","LaMusga factors — 8-factor analysis for joint custody move-aways","Factor 1: children interest in stability and continuity in existing arrangement","Factor 2: distance of move and ease of travel","Factor 3: age of children","Factor 4: children relationship with both parents","Factor 5: relationship between parents — ability to cooperate and communicate","Factor 6: wishes of children if sufficient age and capacity","Factor 7: reasons for proposed move — employment, family, remarriage","Factor 8: extent parents currently share custody","Court may not use move itself to change custody away from moving parent","Good faith requirement: move must not be primarily to frustrate contact","Revised custody/visitation plan must be considered as alternative to custody change","Notice requirement: reasonable advance notice to other parent","Stipulated geographic restriction in custody order may limit right to relocate"]', '[{"section":"7501","description":"Parent entitled to change residence of child unless restricted by court order"},{"section":"Marriage of Burgess (1996) 13 Cal.4th 25","description":"Sole custody: presumptive right to relocate; burden on noncustodial parent"},{"section":"Marriage of LaMusga (2004) 32 Cal.4th 1072","description":"Joint custody: no presumptive right — best interest balancing, 8 factors"},{"section":"Marriage of Condon (1998) 62 Cal.App.4th 533","description":"Move-away with de facto joint custody triggers LaMusga-type analysis"},{"section":"Roe v. Roe","description":"Good faith requirement — move must not be to frustrate other parent contact"},{"section":"Marriage of Edlund & Hales (1998)","description":"Geographic restrictions in custody orders enforceable"},{"section":"FC § 3024","description":"Notice of proposed relocation — 45 days before move"}]', '["move_away_motion","opposition_to_move_away","FL-300","custody_declaration","LaMusga_brief","revised_custody_plan","notice_of_proposed_relocation","vocational_evaluation","child_custody_evaluation","trial_brief"]', '["family-law-custody-audit"]', 'Superior Court — Family Division', 1, 1, datetime('now'), datetime('now'));

-- Paternity / Parentage
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_088', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 7600-7730 (Uniform Parentage Act — UPA)', 'FC §§ 7600-7730 / UPA', 'Paternity and Parentage — Establishment Under the Uniform Parentage Act', 'California''s Uniform Parentage Act (UPA) establishes the framework for determining legal parentage. Parent-child relationship may be established by: (1) giving birth, (2) adjudication of parentage, (3) adoption, (4) voluntary declaration of parentage, (5) presumption under § 7611, or (6) assisted reproduction agreement. Presumed parent status arises under § 7611: married to mother at time of conception/birth, attempted to marry, received child into home and held out as own (Kelsey S. doctrine), or signed voluntary declaration. Presumed parent status may be rebutted only by court finding that presumed parent is not biological parent and that rebuttal is in child''s best interest. Genetic testing may be ordered (§ 7550-7557). Two-year statute of limitations for challenging presumed parentage (§ 7541). Court may find more than two parents in rare cases where recognition of only two would be detrimental to child (§ 7612(c)).', '["Parent-child relationship: same rights regardless of parents marital status (§ 7602)","Presumed parent under § 7611: married at conception/birth, attempted marriage, received child and held out as own","Voluntary Declaration of Parentage: signed at hospital or later — has force of judgment (§ 7573)","Voluntary Declaration may be rescinded within 60 days (§ 7575)","Genetic testing: court may order on motion of any party (§ 7551)","Two-year SOL: action to challenge presumed parentage based on genetic testing (§ 7541)","Kelsey S. doctrine: biological father who promptly comes forward and demonstrates commitment may be presumed parent","Best interest of child: court considers when rebutting presumptions","More than two parents: court may find in rare cases — detriment finding required (§ 7612(c))","Assisted reproduction: person who provides gametes to licensed physician for use by another is not parent (§ 7613)","Surrogacy: gestational (§ 7960+) and traditional surrogacy agreements recognized","Child support obligation follows parentage determination","Local Child Support Agency (LCSA) may bring parentage action (§ 7630)"]', '[{"section":"7600","description":"Short title — Uniform Parentage Act"},{"section":"7602","description":"Parent-child relationship — equal rights regardless of parents marital status"},{"section":"7610","description":"Ways parent-child relationship established"},{"section":"7611","description":"Presumed parent — marriage, attempted marriage, receiving child into home"},{"section":"7612","description":"Rebuttal of presumption — best interest analysis"},{"section":"7612(c)","description":"More than two parents — rare circumstances, detriment finding"},{"section":"7541","description":"Two-year SOL for challenging presumed parentage via genetic testing"},{"section":"7550-7557","description":"Genetic testing — court order, standards, costs"},{"section":"7570-7577","description":"Voluntary Declaration of Parentage — execution, rescission, force of judgment"},{"section":"7630","description":"Action to determine parentage — who may bring"},{"section":"7613","description":"Assisted reproduction — donor not parent unless agreed"},{"section":"7960-7962","description":"Gestational surrogacy agreements"}]', '["parentage_petition","voluntary_declaration_of_parentage","genetic_testing_order","FL-200","FL-220","FL-230","response_to_parentage","judgment_of_parentage","child_support_order","LCSA_complaint","custody_order"]', '["family-law-custody-audit"]', 'Superior Court — Family Division / LCSA', 1, 1, datetime('now'), datetime('now'));

-- Hague Convention on International Child Abduction
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_089', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '22 USC §§ 9001-9011 (International Child Abduction Remedies Act — ICARA) / Hague Convention on the Civil Aspects of International Child Abduction', '22 USC § 9001+ / Hague Convention', 'Hague Convention on International Child Abduction — Return of Wrongfully Removed Children', 'The Hague Convention (1980), implemented in the U.S. by ICARA (22 USC § 9001+), provides a civil mechanism for the prompt return of children wrongfully removed to or retained in a signatory country in breach of custody rights. The Convention does not determine the merits of custody — it restores the status quo ante by returning the child to the country of habitual residence for custody determination. Petitioner must prove by preponderance: (1) child was habitually resident in a Convention country, (2) removal or retention breached petitioner''s custody rights under that country''s law, (3) petitioner was actually exercising custody rights at time of removal. Defenses (respondent''s burden): (1) proceeding commenced more than 1 year after wrongful removal and child is settled (Article 12), (2) petitioner was not exercising custody rights or consented/acquiesced (Article 13a), (3) grave risk of physical or psychological harm (Article 13b — clear and convincing evidence), (4) child objects and has attained sufficient age and maturity (Article 13), (5) return would violate fundamental principles of human rights (Article 20). U.S. Central Authority: Office of Children''s Issues, U.S. State Department.', '["Civil remedy for prompt return of wrongfully removed/retained children","Applies between signatory (Contracting State) countries only","Does NOT determine custody merits — restores status quo for home country to decide","Habitual residence: factual determination — child center of life analysis","Petitioner burden (preponderance): habitual residence + breach of custody rights + exercising custody","Custody rights: may arise by operation of law, court order, or agreement (Article 3)","Wrongful removal or retention: in breach of rights of custody under law of habitual residence","One-year rule: if petition filed within 1 year, return is mandatory (absent defenses)","After 1 year: return unless child is settled in new environment (Article 12)","Defense — consent or acquiescence by left-behind parent (Article 13a)","Defense — grave risk of physical or psychological harm to child (Article 13b) — clear and convincing","Defense — child objects to return and is of sufficient age/maturity (Article 13)","Defense — fundamental principles of human rights of requested state (Article 20)","Ne exeat rights: right to determine child residence constitutes custody rights (Abbott v. Abbott)","ICARA: federal or state court jurisdiction — concurrent (22 USC § 9003)","No bond required for filing — court may award fees and costs to prevailing petitioner (22 USC § 9007)","Central Authority (US): Office of Children Issues, U.S. Department of State"]', '[{"section":"22 USC § 9001","description":"Congressional findings and declarations — ICARA"},{"section":"22 USC § 9003","description":"Jurisdiction — concurrent federal and state court"},{"section":"22 USC § 9004","description":"Provisional remedies — locating child, preventing further removal"},{"section":"22 USC § 9007","description":"Costs and fees — court may award to prevailing petitioner"},{"section":"Article 3","description":"Wrongful removal defined — breach of custody rights"},{"section":"Article 12","description":"Return ordered if within 1 year; after 1 year if child not settled"},{"section":"Article 13a","description":"Defense: consent or acquiescence"},{"section":"Article 13b","description":"Defense: grave risk of harm — clear and convincing evidence"},{"section":"Article 20","description":"Defense: fundamental principles of human rights"},{"section":"Abbott v. Abbott (2010)","description":"Ne exeat rights constitute rights of custody under Convention"}]', '["Hague_petition","ICARA_complaint","return_order","provisional_remedies_motion","grave_risk_defense","habitual_residence_brief","Central_Authority_application","ne_exeat_order","declaration","expert_report_country_conditions"]', '["family-law-custody-audit"]', 'Federal Court / State Court (concurrent) / U.S. Central Authority (Dept. of State)', 1, 1, datetime('now'), datetime('now'));


