-- PC § 836 — Warrantless Arrest Authority
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_181', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 836 (Warrantless Arrest by Peace Officer)', 'PC § 836', 'Warrantless Arrest Authority — Peace Officer Arrest Without Warrant', 'A peace officer may make an arrest without a warrant: (1) whenever the officer has probable cause to believe the person has committed a public offense in the officer''s presence, (2) when the person has committed a felony although not in the officer''s presence, (3) whenever the officer has probable cause to believe the person has committed a felony whether or not a felony has in fact been committed. For misdemeanor domestic violence (PC § 243(e)(1), § 273.5), mandatory arrest is required when the officer has probable cause and the offense occurred within the preceding 4 hours, even though not committed in the officer''s presence (§ 836(d)). Officers must inform the person of the authority and cause of arrest unless impractical (PC § 841). Citizen''s arrest under PC § 837 is a separate and more limited authority.', '["Arrest without warrant: probable cause for public offense in presence (§ 836(a)(1))","Arrest without warrant: person committed felony not in presence (§ 836(a)(2))","Arrest without warrant: probable cause to believe felony committed (§ 836(a)(3))","Misdemeanor arrest generally requires offense committed in presence (except DV exceptions)","DV mandatory arrest: probable cause + misdemeanor DV + within past 4 hours (§ 836(d))","DV mandatory arrest applies to PC § 243(e)(1) and PC § 273.5","Officer must determine dominant aggressor before DV arrest (§ 836(c)(3))","Dominant aggressor: consider threats, history, severity of injuries, likelihood of future injury","Officer must inform arrested person of authority and cause (PC § 841)","Probable cause: objective standard — reasonable person would believe offense committed","Good faith immunity: officer acting in good faith under apparent authority (GC § 820.4)","Citizen arrest (PC § 837): public offense in presence, or felony actually committed"]', '[{"section":"836(a)(1)","description":"Warrantless arrest — public offense committed in officer presence"},{"section":"836(a)(2)","description":"Warrantless arrest — felony committed not in presence"},{"section":"836(a)(3)","description":"Warrantless arrest — probable cause to believe felony committed"},{"section":"836(c)(1)","description":"Officer responding to DV call — make report even if no arrest"},{"section":"836(c)(3)","description":"Dominant aggressor determination before DV arrest"},{"section":"836(d)","description":"Mandatory warrantless arrest for misdemeanor DV within 4 hours"},{"section":"837","description":"Citizen arrest — public offense in presence or felony actually committed"},{"section":"841","description":"Officer must inform of authority and cause of arrest"},{"section":"840","description":"Misdemeanor arrest: in presence or DV exception"}]', '["arrest_report","probable_cause_declaration","booking_sheet","DV_incident_report","dominant_aggressor_determination","citizen_arrest_form","complaint","1983_complaint_false_arrest"]', '["ca-post-law-enforcement-audit"]', 'Law Enforcement Agency / District Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- PC § 243(e)(1) — Battery Against Spouse/Cohabitant
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_182', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 243(e)(1) (Battery Against Spouse, Cohabitant, or Fellow Parent)', 'PC § 243(e)(1)', 'Battery Against Spouse, Cohabitant, Former Spouse, or Parent of Child — Misdemeanor', 'Battery committed against a spouse, a person with whom the defendant is cohabiting, a person who is the parent of the defendant''s child, a former spouse, a fiancé or fiancée, or a person with whom the defendant currently has or has previously had a dating or engagement relationship is a misdemeanor punishable by a fine up to $2,000, imprisonment in county jail up to one year, or both. No visible injury is required — any willful and unlawful use of force or violence upon another person. This is the misdemeanor DV battery charge — distinguished from PC § 273.5 which requires traumatic condition (visible injury). Upon conviction, court must order 52-week batterer intervention program (PC § 1203.097). Probation conditions include protective order, restitution, and mandatory DV program. Prior convictions enhance sentencing.', '["Battery: any willful and unlawful use of force or violence upon another (§ 242)","No visible injury required — distinguishes from PC § 273.5 (corporal injury)","Protected persons: spouse, cohabitant, parent of child, former spouse, fiancé, dating relationship","Misdemeanor: up to 1 year county jail and/or $2,000 fine","Probation: mandatory 52-week batterer intervention program (§ 1203.097)","Probation conditions: protective order, restitution, community service, mandatory DV program","Protective order: court must consider issuing upon conviction (§ 136.2)","Mandatory arrest: officer must arrest if probable cause + within 4 hours (§ 836(d))","Enhancement: prior DV convictions may increase sentencing","Conviction bars firearm possession for 10 years (PC § 29805) and life under federal law (18 USC § 922(g)(9))","Often charged as alternative to PC § 273.5 when no visible injury","Diversion may be available for first-time offenders (PC § 1001.94-1001.98)"]', '[{"section":"242","description":"Battery defined — willful and unlawful use of force or violence"},{"section":"243(e)(1)","description":"Battery against spouse/cohabitant/fellow parent — misdemeanor"},{"section":"243(e)(2)","description":"Minimum fine $500 if probation granted and no imprisonment"},{"section":"1203.097","description":"Mandatory 52-week batterer intervention program on DV probation"},{"section":"136.2","description":"Protective order upon DV conviction"},{"section":"836(d)","description":"Mandatory warrantless arrest for DV misdemeanor within 4 hours"},{"section":"29805","description":"10-year firearm prohibition upon DV misdemeanor conviction"},{"section":"18 USC 922(g)(9)","description":"Federal lifetime firearm prohibition — Lautenberg Amendment"}]', '["criminal_complaint","arrest_report","DV_incident_report","protective_order","probation_conditions","batterer_intervention_enrollment","plea_agreement","sentencing_brief","firearm_relinquishment"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / City Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

