INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_183', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 273.5 (Corporal Injury on Spouse, Cohabitant, or Fellow Parent)', 'PC § 273.5', 'Corporal Injury Resulting in Traumatic Condition — Felony/Misdemeanor DV', 'Any person who willfully inflicts corporal injury resulting in a traumatic condition upon a victim who is the person''s spouse, former spouse, cohabitant, former cohabitant, parent of the person''s child, or person with whom the defendant currently has or previously had a dating relationship is guilty of a felony or misdemeanor. Traumatic condition is defined as a condition of the body, such as a wound, or external or internal injury, including injury from strangulation or suffocation, whether of a minor or serious nature, caused by a physical force (§ 273.5(d)). This is the primary felony DV charge — requires visible injury (traumatic condition), distinguishing it from PC § 243(e)(1). Wobbler: punishable by 2, 3, or 4 years state prison (felony) or up to 1 year county jail (misdemeanor). Prior convictions within 7 years trigger enhanced sentencing (§ 273.5(f)).', '["Willful infliction of corporal injury resulting in traumatic condition","Traumatic condition: wound or injury caused by physical force — minor or serious (§ 273.5(d))","Includes strangulation and suffocation injuries (§ 273.5(d))","Protected victims: spouse, former spouse, cohabitant, former cohabitant, parent of child, dating partner","Wobbler: felony (2/3/4 years state prison) or misdemeanor (up to 1 year county jail)","Great bodily injury enhancement: additional 3-5 years (§ 12022.7)","Prior DV conviction within 7 years: enhanced penalty (§ 273.5(f))","Prior 273.5 conviction within 7 years: 2/4/5 years state prison (§ 273.5(f)(1))","Prior 243(e)(1), 243(d), 244, 245, or 273.5: 2/3/4 years (§ 273.5(f)(2))","Mandatory 52-week batterer intervention on probation (§ 1203.097)","Protective order required (§ 136.2)","Firearm prohibition: felony = lifetime; misdemeanor = 10 years (§ 29805)","Strike offense if great bodily injury found (Three Strikes Law)","Mandatory arrest if probable cause + within 4 hours (§ 836(d))"]', '[{"section":"273.5(a)","description":"Willful infliction of corporal injury — traumatic condition on protected person"},{"section":"273.5(d)","description":"Traumatic condition defined — wound or injury from physical force, including strangulation"},{"section":"273.5(f)(1)","description":"Prior 273.5 within 7 years — enhanced sentencing 2/4/5 years"},{"section":"273.5(f)(2)","description":"Prior DV conviction within 7 years — enhanced 2/3/4 years"},{"section":"12022.7","description":"Great bodily injury enhancement — 3-5 additional years"},{"section":"1203.097","description":"Mandatory batterer intervention program on DV probation"},{"section":"136.2","description":"Protective order upon DV conviction"},{"section":"836(d)","description":"Mandatory warrantless arrest for DV within 4 hours"}]', '["criminal_complaint","felony_information","arrest_report","medical_records","injury_photographs","DV_incident_report","protective_order","probation_conditions","preliminary_hearing_transcript","sentencing_brief"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- PC § 166 — Contempt of Court
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_184', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 166 (Contempt of Court — Violation of Court Order)', 'PC § 166', 'Contempt of Court — Criminal Contempt for Violation of Court Order', 'A person guilty of contempt of court includes one who willfully disobeys any process or order lawfully issued by any court. PC § 166(a)(4): willful disobedience of any lawfully issued court order is a misdemeanor. PC § 166(c)(1): violation of a protective order issued under the DVPA (FC § 6300+), CCP § 527.6, or similar provisions is punishable by imprisonment in county jail up to one year, a fine up to $1,000, or both. Second or subsequent violation of a DV protective order involving an act of violence or credible threat of violence is a wobbler — felony punishable by 16 months, 2, or 3 years state prison (§ 166(c)(4)). Elements: (1) valid court order, (2) knowledge of the order, (3) ability to comply, (4) willful failure to comply. Court may also impose civil contempt under CCP § 1209-1222 (remedial/coercive rather than punitive).', '["Misdemeanor: willful disobedience of lawfully issued court order (§ 166(a)(4))","First offense DV protective order violation: misdemeanor — up to 1 year, $1,000 fine (§ 166(c)(1))","Second+ DV protective order violation with violence/threat: wobbler — up to 3 years prison (§ 166(c)(4))","Elements: valid order + knowledge + ability to comply + willful violation","Knowledge: actual knowledge of order; may be proven by service, presence in court, or CLETS","Willful: intentional disregard — not mere inability to comply","Valid order: order must be lawfully issued by court of competent jurisdiction","DV protective orders: DVRO (FC § 6300+), CHO (CCP § 527.6), EPO, CPO","Protective order must be in CLETS for enforcement","Concurrent jurisdiction: criminal contempt (PC § 166) and civil contempt (CCP § 1209+)","Civil contempt: coercive — remedy is compliance; purge condition","Criminal contempt: punitive — punishment for past violation","Violation of custody/visitation orders may also constitute contempt","Contempt power is inherent in all courts"]', '[{"section":"166(a)(1)","description":"Disorderly behavior in court presence"},{"section":"166(a)(4)","description":"Willful disobedience of court order — misdemeanor"},{"section":"166(b)(1)","description":"Violation of protective order — first offense misdemeanor"},{"section":"166(c)(1)","description":"DV protective order violation — up to 1 year, $1,000 fine"},{"section":"166(c)(4)","description":"Second+ DV order violation with violence — wobbler, up to 3 years"},{"section":"CCP 1209","description":"Civil contempt — acts constituting contempt of court"},{"section":"CCP 1218","description":"Civil contempt penalties — $1,000 fine and/or 5 days jail per count"},{"section":"CCP 1219","description":"No contempt imprisonment for victim of DV who refuses to testify"},{"section":"273.6","description":"Separate criminal statute for DV protective order violation"}]', '["contempt_motion","criminal_complaint","arrest_report","proof_of_service_of_order","CLETS_printout","declaration_of_violation","protective_order","OSC_re_contempt","civil_contempt_petition"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / City Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- PC § 273a — Child Endangerment
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_185', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 273a (Child Endangerment — Willful Harm or Endangerment of Child)', 'PC § 273a', 'Child Endangerment — Willful Cruelty or Unjustifiable Punishment of a Child', 'Any person who under circumstances or conditions likely to produce great bodily harm or death willfully causes or permits any child to suffer, or inflicts thereon unjustifiable physical pain or mental suffering, or willfully causes or permits the child to be placed in a situation where their person or health is endangered, is guilty of a felony (§ 273a(a)). If the circumstances are not likely to produce great bodily harm or death, it is a misdemeanor (§ 273a(b)). This is a general intent crime — prosecution need not prove specific intent to harm the child. Wobbler based on severity of circumstances. Commonly charged alongside DV offenses, DUI with children in vehicle, and child abuse. Mandatory child abuse reporting obligations (PC § 11164+) may trigger investigation. Conviction may affect custody/visitation in family court.', '["Felony (§ 273a(a)): circumstances likely to produce great bodily harm or death","Misdemeanor (§ 273a(b)): circumstances not likely to produce GBH or death","Acts: willfully cause/permit child to suffer; inflict unjustifiable pain/suffering; endanger health","General intent crime: no specific intent to harm required","Willfully: purposeful act — not accident or misfortune","Includes acts of omission: permitting child to be placed in dangerous situation","Child: person under 18 years of age","Felony: 2/4/6 years state prison","Misdemeanor: up to 1 year county jail","Probation conditions: parenting classes, protective order, no contact with children if appropriate","Strike offense if child suffers great bodily injury (§ 12022.7 enhancement)","Mandatory reporting: child abuse triggers PC § 11164+ reporting obligations","CPS/DCFS investigation may result from criminal charge","Conviction impacts custody/visitation in family court — presumption against custody (FC § 3044 for DV)","Commonly charged with: DV offenses, DUI with minor in vehicle (VC § 23572), child abuse"]', '[{"section":"273a(a)","description":"Felony child endangerment — circumstances likely to produce GBH/death"},{"section":"273a(b)","description":"Misdemeanor child endangerment — circumstances not likely GBH/death"},{"section":"273d","description":"Corporal punishment or injury to child — related felony"},{"section":"11164-11174.3","description":"Child Abuse and Neglect Reporting Act (CANRA) — mandatory reporting"},{"section":"12022.7","description":"Great bodily injury enhancement — 3-5 additional years"},{"section":"FC § 3044","description":"Presumption against custody for DV perpetrator — applies to child abuse"}]', '["criminal_complaint","arrest_report","CPS_referral","DCFS_report","medical_records","child_interview","protective_order","sentencing_brief","probation_conditions","mandatory_reporter_form"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / Superior Court / CPS-DCFS', 0, 1, datetime('now'), datetime('now'));

-- PC §§ 136.1-140 — Witness Intimidation
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_186', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 136.1-140 (Intimidation of Witnesses and Victims)', 'PC §§ 136.1-140', 'Witness Intimidation and Dissuading — Preventing Testimony or Reporting', 'PC § 136.1 makes it a crime to knowingly and maliciously prevent or dissuade, or attempt to prevent or dissuade, any witness or victim from attending or giving testimony at any trial, proceeding, or inquiry authorized by law, or from making a report to any peace officer or other designated official. Wobbler: misdemeanor or felony. Felony if accompanied by force, threat of force or violence, or if done in furtherance of conspiracy. PC § 137: offering bribes to influence testimony. PC § 138: accepting bribes to influence testimony. PC § 139: threatening witness/victim who has testified (post-testimony intimidation). PC § 140: threatening a witness or victim or their immediate family. Conviction under § 136.1 is a strike under Three Strikes if force or threat used.', '["Dissuading witness/victim from testifying or reporting (§ 136.1(a))","Dissuading victim from seeking arrest or prosecution (§ 136.1(b)(1))","Dissuading victim from cooperating in prosecution (§ 136.1(b)(2))","Dissuading victim from cooperating in investigation (§ 136.1(b)(3))","Knowingly and maliciously: specific intent required","Wobbler: misdemeanor or felony","Felony if accompanied by: force, express/implied threat of force or violence (§ 136.1(c)(1))","Felony if done in furtherance of conspiracy (§ 136.1(c)(2))","Felony if hired or for financial gain (§ 136.1(c)(3))","Felony penalty: 2/3/4 years state prison","Strike offense if force or threat used (§ 136.1(c) — serious felony under § 1192.7(c)(37))","Attempt is sufficient — actual prevention of testimony not required","Bribery of witness: § 137 — offering money or benefit to influence testimony","Accepting bribe: § 138 — witness accepting consideration to influence testimony","Post-testimony threats: § 139 — threatening witness who has testified — felony","Threatening witness/victim or family: § 140 — misdemeanor, or felony if prior conviction"]', '[{"section":"136.1(a)","description":"Prevent or dissuade witness from attending or testifying"},{"section":"136.1(b)","description":"Prevent or dissuade victim from reporting, cooperating, prosecuting"},{"section":"136.1(c)","description":"Aggravated: force, threat, conspiracy — felony with strike"},{"section":"137","description":"Bribery of witness — offering consideration to influence testimony"},{"section":"138","description":"Witness accepting bribe — receiving consideration for testimony"},{"section":"139","description":"Post-testimony threats — threatening witness who testified"},{"section":"140","description":"Threatening witness, victim, or immediate family — misdemeanor/felony"},{"section":"136.2","description":"Protective orders in criminal cases — court shall consider issuing"},{"section":"1192.7(c)(37)","description":"Serious felony designation — strike offense"}]', '["criminal_complaint","arrest_report","witness_statement","protective_order","threat_evidence","communication_records","preliminary_hearing_transcript","sentencing_brief","victim_declaration","Three_Strikes_allegation"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- PC § 653m — Annoying/Threatening Phone Calls
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_187', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 653m (Annoying or Threatening Phone Calls and Electronic Communications)', 'PC § 653m', 'Annoying or Threatening Phone Calls and Electronic Communications — Misdemeanor', 'Every person who, with intent to annoy, telephones or makes contact by means of an electronic communication device with another and addresses to or about the other person any obscene language or addresses to the other person any threat to inflict injury to the person or property of the person addressed or any member of their family, is guilty of a misdemeanor (§ 653m(a)). Also prohibited: repeated telephone calls or electronic contacts with intent to annoy, where conversation ensues, regardless of content (§ 653m(b)). Electronic communication includes text messages, emails, social media messages, and other digital communications. Commonly charged in DV and harassment contexts. May support issuance of restraining orders (DVRO, CHO). Intent to annoy is subjective — determined by totality of circumstances.', '["Obscene language or threats via phone/electronic communication — misdemeanor (§ 653m(a))","Intent to annoy required — subjective intent, proven by circumstances","Threats to injure person or property of recipient or their family","Repeated calls/contacts with intent to annoy — regardless of content (§ 653m(b))","Electronic communication: telephone, text, email, social media, any electronic device","Misdemeanor: up to 6 months county jail and/or $1,000 fine","May be charged alongside stalking (PC § 646.9), criminal threats (PC § 422), harassment","Commonly arises in DV and harassment contexts","Evidence: phone records, text messages, voicemails, social media screenshots","May support issuance of DVRO (FC § 6300+) or CHO (CCP § 527.6)","Probation conditions may include no-contact order","Federal: 47 USC § 223 — similar federal prohibition on harassing communications"]', '[{"section":"653m(a)","description":"Obscene language or threats via phone/electronic communication"},{"section":"653m(b)","description":"Repeated calls/contacts with intent to annoy — regardless of content"},{"section":"653m(c)","description":"Electronic communication device defined"},{"section":"646.9","description":"Stalking — related felony/misdemeanor"},{"section":"422","description":"Criminal threats — related felony/misdemeanor"},{"section":"47 USC § 223","description":"Federal: harassing telephone/electronic communications"}]', '["criminal_complaint","arrest_report","phone_records","text_message_screenshots","voicemail_recordings","social_media_printouts","restraining_order_petition","protective_order","witness_statement"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / City Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- Vehicle Code § 14601 — Driving on Suspended License
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_188', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Vehicle Code §§ 14601-14601.5 (Driving on Suspended or Revoked License)', 'VC §§ 14601-14601.5', 'Driving on Suspended or Revoked License — Criminal Violations', 'Driving a motor vehicle with knowledge that the driver''s license has been suspended or revoked is a misdemeanor. Multiple subsections address different bases for suspension: VC § 14601 — general suspension/revocation (knowledge required); VC § 14601.1 — suspension for reasons other than DUI/negligent operator (knowledge or constructive knowledge); VC § 14601.2 — DUI-related suspension (mandatory jail, enhanced penalties); VC § 14601.5 — suspension for refusal to submit to chemical test or excessive BAC. Penalties escalate with repeat offenses and include mandatory jail (for DUI-related), fines, vehicle impoundment, and probation. Knowledge element: actual knowledge or constructive knowledge (DMV mailing to last known address creates rebuttable presumption of knowledge). Common charge in DV contexts where license suspended due to failure to appear (FTA) or failure to pay (FTP).', '["§ 14601: driving while suspended/revoked — general — knowledge required","§ 14601.1: driving on suspension — non-DUI reasons — knowledge or constructive knowledge","§ 14601.2: driving on DUI-related suspension — mandatory minimum jail","§ 14601.5: driving on suspension for chemical test refusal or BAC","Knowledge element: actual or constructive (DMV mailing creates rebuttable presumption)","§ 14601: misdemeanor — 5 days to 6 months jail, $300-$1,000 fine (first offense)","§ 14601.2: misdemeanor — 10 days to 1 year jail, $500-$2,000 fine (first DUI suspension)","Repeat offenses: escalating mandatory minimums","Vehicle impoundment: 30 days (§ 14602.6)","Probation conditions: no driving without valid license","SR-22 insurance requirement for license reinstatement","Installation of ignition interlock device may be required (DUI cases)","Commonly arises where license suspended for FTA/FTP in unrelated cases","Enhancement: causing injury while driving on suspended license (VC § 14601.4 — wobbler)"]', '[{"section":"14601","description":"General: driving on suspended/revoked license — knowledge required"},{"section":"14601.1","description":"Non-DUI suspension: driving with knowledge or constructive knowledge"},{"section":"14601.2","description":"DUI-related suspension: mandatory jail, enhanced fines"},{"section":"14601.4","description":"Causing injury while driving on suspended — wobbler"},{"section":"14601.5","description":"Suspension for chemical test refusal or BAC — driving prohibited"},{"section":"14602.6","description":"Vehicle impoundment — 30 days for driving on suspended"},{"section":"12500","description":"Driving without license — related but distinct offense"},{"section":"40509.5","description":"FTA suspension — basis for license suspension"}]', '["criminal_complaint","traffic_citation","DMV_printout","booking_sheet","vehicle_impound_notice","proof_of_insurance_SR22","probation_conditions","motion_to_dismiss","license_reinstatement"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / City Attorney / DMV / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- PC § 602 — Trespass
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_189', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 602 (Trespass)', 'PC § 602', 'Trespass — Unauthorized Entry or Remaining on Property', 'PC § 602 enumerates numerous forms of criminal trespass. Key subsections: § 602(m) — entering and occupying real property without consent of owner; § 602(n) — driving a vehicle upon real property without consent and refusing to leave upon request; § 602(o) — refusing or failing to leave land, real property, or structures belonging to or lawfully occupied by another and not open to the general public upon request of the owner or authorized agent; § 602(k) — entering lands enclosed by fence for purpose of injuring property or livestock. General trespass is a misdemeanor punishable by up to 6 months county jail and/or $1,000 fine. Aggravated trespass (PC § 601): making a credible threat and then within 30 days entering the victim''s workplace or residence — wobbler. Trespass is frequently charged in DV contexts where a restrained party enters or remains at the protected party''s residence.', '["§ 602(m): entering and occupying property without consent","§ 602(n): driving vehicle on property without consent, refusing to leave","§ 602(o): refusing/failing to leave upon request of owner — most commonly charged","§ 602(k): entering fenced lands to injure property or livestock","§ 602(l): entering posted property without consent — land, buildings","General trespass: misdemeanor — up to 6 months county jail, $1,000 fine","Infraction: § 602(t) — entering posted commercial property, first offense","Aggravated trespass (§ 601): credible threat + entry within 30 days — wobbler","§ 601 felony: 16 months, 2, or 3 years state prison","§ 601 misdemeanor: up to 1 year county jail","Must leave upon request: owner, agent, or peace officer demand","Commonly charged in DV contexts: restrained party enters protected party residence","Trespass may violate restraining order — concurrent PC § 166 charge","Civil trespass: separate tort action for damages (Civ. Code § 1714)"]', '[{"section":"602(m)","description":"Entering and occupying property without consent"},{"section":"602(n)","description":"Driving on property without consent, refusing to leave"},{"section":"602(o)","description":"Refusing to leave upon request of owner or authorized agent"},{"section":"602(k)","description":"Entering fenced lands to damage property"},{"section":"602(l)","description":"Entering posted property without consent"},{"section":"602(t)","description":"Entering posted commercial property — infraction"},{"section":"601","description":"Aggravated trespass: credible threat + entry within 30 days — wobbler"},{"section":"602.5","description":"Unauthorized entry into dwelling — misdemeanor (distinct from burglary)"},{"section":"Civ. Code 1714","description":"Civil trespass — tort action for damages"}]', '["criminal_complaint","arrest_report","property_owner_statement","no_trespass_notice","photographs","restraining_order","booking_sheet","probation_conditions","civil_complaint_trespass"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / City Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));

-- PC § 459/460 — Burglary
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_190', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 459-460 (Burglary — First and Second Degree)', 'PC §§ 459-460', 'Burglary — Entry into Structure with Intent to Commit Felony or Theft', 'Every person who enters any house, room, apartment, tenement, shop, warehouse, store, mill, barn, stable, outhouse, or other building, tent, vessel, floating home, railroad car, locked or sealed cargo container, house car, inhabited camper, vehicle when the doors are locked, aircraft, mine, or underground portion of any mine with intent to commit grand or petit larceny or any felony is guilty of burglary (§ 459). First degree burglary (§ 460(a)): burglary of an inhabited dwelling house or inhabited portion of any building — always a felony, punishable by 2, 4, or 6 years state prison. First degree residential burglary is a strike under Three Strikes. Second degree burglary (§ 460(b)): all other burglaries — wobbler. Elements: (1) entry into a structure, (2) with intent to commit theft or any felony at the time of entry. Intent must exist at the time of entry. Prop 47 reclassified shoplifting (entry into commercial establishment during business hours with intent to steal $950 or less) as misdemeanor (PC § 459.5).', '["Entry into specified structure with intent to commit felony or theft at time of entry (§ 459)","First degree (§ 460(a)): inhabited dwelling — always felony — 2/4/6 years state prison","Second degree (§ 460(b)): all other structures — wobbler — felony or misdemeanor","First degree residential burglary: serious felony (§ 1192.7(c)(18)) — Three Strikes","Inhabited: currently being used for dwelling purposes, whether or not occupied at time of entry","Entry: any part of body or instrument crossing threshold with requisite intent","Intent must exist at time of entry — subsequent formation of intent not sufficient","Person who enters own home may commit burglary if intent to commit felony against another occupant (People v. Gauze exception)","Felony second degree: 16 months, 2, or 3 years county jail (§ 1170(h))","Misdemeanor second degree: up to 1 year county jail","Shoplifting (§ 459.5): entry into commercial establishment during business hours, intent to steal ≤$950 — misdemeanor (Prop 47)","Burglary tools: possession of burglary tools with intent to use — misdemeanor (PC § 466)","Auto burglary: second degree — entry into locked vehicle","Commonly charged in DV contexts: entry into former shared residence in violation of court order"]', '[{"section":"459","description":"Burglary defined — entry with intent to commit felony or theft"},{"section":"460(a)","description":"First degree: inhabited dwelling — felony, 2/4/6 years prison"},{"section":"460(b)","description":"Second degree: all other structures — wobbler"},{"section":"459.5","description":"Shoplifting: commercial establishment, business hours, ≤$950 — misdemeanor (Prop 47)"},{"section":"461","description":"Punishment: first degree 2/4/6 years; second degree 16mo/2/3 years or misdemeanor"},{"section":"466","description":"Burglary tools: possession with intent — misdemeanor"},{"section":"1192.7(c)(18)","description":"Residential burglary: serious felony — Three Strikes"},{"section":"People v. Gauze","description":"Cannot burglarize own home — exception for DV situations with court orders"}]', '["criminal_complaint","felony_information","arrest_report","search_warrant","crime_scene_report","fingerprint_evidence","surveillance_footage","preliminary_hearing_transcript","sentencing_brief","Three_Strikes_allegation","restitution_order"]', '["ca-post-law-enforcement-audit"]', 'District Attorney / Superior Court', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- ETHICARA — Medical Fraud / Billing
-- ═══════════════════════════════════════════════════════════════════════════

-- False Claims — Medicare/Medi-Cal Fraud
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_086', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 12650-12656 (California False Claims Act) + 31 USC §§ 3729-3733 (Federal False Claims Act)', 'GC § 12651 / 31 USC § 3729 / FCA', 'False Claims Act — Medicare and Medi-Cal Fraud — Qui Tam Whistleblower Actions', 'The Federal False Claims Act (31 USC § 3729) and California False Claims Act (GC § 12650) impose civil liability on any person who knowingly submits a false or fraudulent claim for payment to the government. In the healthcare context, this is the primary tool for combating Medicare and Medi-Cal billing fraud. Knowingly includes: actual knowledge, deliberate ignorance, or reckless disregard of truth or falsity. Qui tam (whistleblower) provision: private persons (relators) may bring actions on behalf of the government and receive 15-30% of recovery. Federal penalties: treble damages plus $13,946-$27,894 per false claim (2024 adjusted). California penalties: treble damages plus $11,000 per false claim. Examples: billing for services not rendered, upcoding, unbundling, billing for medically unnecessary procedures, falsifying medical records to justify billing. 6-year statute of limitations (federal), 3 years after discovery but no more than 10 years (whichever later under federal FCA). Anti-retaliation protections for whistleblowers (31 USC § 3730(h)).', '["False claim: knowingly presenting false/fraudulent claim for payment to government","Knowingly: actual knowledge, deliberate ignorance, or reckless disregard (§ 3729(b))","No specific intent to defraud required — reckless disregard sufficient","Qui tam: private relator files under seal; government decides whether to intervene","Relator share: 15-25% if government intervenes; 25-30% if relator proceeds alone","Federal penalties: treble damages + $13,946-$27,894 per false claim (2024)","California penalties: treble damages + $11,000 per false claim (GC § 12651(a))","Healthcare fraud examples: billing for services not rendered, upcoding, unbundling","Falsifying medical records to support false billing","Medically unnecessary procedures billed to Medicare/Medi-Cal","Reverse false claim: knowingly concealing or avoiding obligation to pay government","SOL: 6 years from violation or 3 years from discovery (max 10 years) — whichever later","Anti-retaliation: whistleblower protected from employer retaliation (§ 3730(h))","California Insurance Fraud Prevention Act (Ins. Code § 1871) — related","DOJ Civil Division and OIG are primary federal enforcement agencies"]', '[{"section":"31 USC § 3729(a)","description":"Federal FCA — liability for false claims, seven bases"},{"section":"31 USC § 3729(b)","description":"Knowingly defined — actual knowledge, deliberate ignorance, reckless disregard"},{"section":"31 USC § 3730(b)","description":"Qui tam procedure — filing under seal, government intervention decision"},{"section":"31 USC § 3730(d)","description":"Relator share — 15-30% of recovery"},{"section":"31 USC § 3730(h)","description":"Anti-retaliation — whistleblower employment protections"},{"section":"31 USC § 3731(b)","description":"Statute of limitations — 6 years or 3 from discovery (max 10)"},{"section":"GC § 12651(a)","description":"California FCA — false claims, treble damages + $11,000 per claim"},{"section":"GC § 12652(c)","description":"California qui tam procedure"},{"section":"GC § 12653","description":"Anti-retaliation — California whistleblower protections"}]', '["qui_tam_complaint","FCA_complaint","relator_declaration","billing_records","medical_records","coding_audit","statistical_sampling","CMS_claim_data","DOJ_intervention_notice","settlement_agreement","corporate_integrity_agreement","anti_retaliation_complaint"]', '["medical-billing-surgery-fraud-audit"]', 'DOJ / HHS-OIG / California AG / Medi-Cal Fraud Control Unit / Federal/State Courts', 1, 1, datetime('now'), datetime('now'));

-- Anti-Kickback Statute
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_087', 'ETHICARA', 'FEDERAL_STATUTE', 'US', '42 USC § 1320a-7b(b) (Anti-Kickback Statute — AKS)', '42 USC § 1320a-7b(b) / AKS', 'Anti-Kickback Statute — Prohibition on Healthcare Referral Kickbacks', 'The Anti-Kickback Statute (AKS) makes it a criminal offense to knowingly and willfully offer, pay, solicit, or receive any remuneration (including kickbacks, bribes, or rebates) directly or indirectly to induce or reward referrals of items or services reimbursable by a federal healthcare program (Medicare, Medicaid, Medi-Cal, TRICARE, etc.). Both the offeror/payor and the recipient are liable. Criminal penalties: up to $100,000 fine and 10 years imprisonment per violation. Civil monetary penalties: up to $100,000 per violation. Exclusion from federal healthcare programs. Claims resulting from AKS violations are automatically false claims under FCA (per ACA § 6402). Safe harbors (42 CFR § 1001.952) protect specified payment arrangements: investment interests, personal services, rental agreements, discounts, employee compensation, group purchasing, and others. One purpose test: if even one purpose of the remuneration is to induce referrals, the statute is violated (until recent legislative changes requiring proof of willfulness).', '["Criminal prohibition: offering, paying, soliciting, or receiving remuneration to induce referrals","Both sides liable: payor/offeror and recipient/solicitor","Federal healthcare programs: Medicare, Medicaid/Medi-Cal, TRICARE, VA, CHIP","Remuneration: anything of value — cash, gifts, free services, below-market rent, lavish dinners","One purpose test: if any purpose is to induce referrals, AKS violated","Criminal penalties: up to $100,000 fine and 10 years imprisonment per violation","Civil monetary penalties: up to $100,000 per violation (42 USC § 1320a-7a)","Exclusion from federal healthcare programs (42 USC § 1320a-7)","ACA § 6402: AKS violation = automatic false claim under FCA","Safe harbors: 42 CFR § 1001.952 — enumerated protected arrangements","Safe harbor examples: bona fide employment, personal services contracts, fair market value rent","Safe harbor: investment interests in large publicly traded entities","Safe harbor: discounts properly disclosed and reported","OIG Advisory Opinions: guidance on specific arrangements","Failure to meet safe harbor does not automatically mean violation — facts and circumstances","Intent: knowingly and willfully — government must prove intent to induce referrals"]', '[{"section":"1320a-7b(b)(1)","description":"Criminal prohibition — offering or paying remuneration for referrals"},{"section":"1320a-7b(b)(2)","description":"Criminal prohibition — soliciting or receiving remuneration for referrals"},{"section":"42 CFR 1001.952","description":"Safe harbors — enumerated protected payment arrangements"},{"section":"1320a-7a","description":"Civil monetary penalties — up to $100,000 per violation"},{"section":"1320a-7","description":"Exclusion from federal healthcare programs"},{"section":"ACA § 6402","description":"AKS violation constitutes automatic false claim under FCA"},{"section":"OIG Advisory Opinions","description":"Guidance on whether specific arrangements implicate AKS"}]', '["criminal_complaint","OIG_investigation","civil_monetary_penalty","exclusion_notice","corporate_integrity_agreement","safe_harbor_analysis","OIG_advisory_opinion","billing_records","referral_records","compensation_agreements","FCA_complaint","settlement_agreement"]', '["medical-billing-surgery-fraud-audit"]', 'HHS-OIG / DOJ / State AG / Federal Courts', 0, 1, datetime('now'), datetime('now'));

-- Stark Law — Physician Self-Referral
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_088', 'ETHICARA', 'FEDERAL_STATUTE', 'US', '42 USC § 1395nn (Stark Law — Physician Self-Referral Prohibition)', '42 USC § 1395nn / Stark Law', 'Stark Law — Physician Self-Referral Prohibition for Designated Health Services', 'The Stark Law (Physician Self-Referral Law) prohibits a physician from making referrals for designated health services (DHS) payable by Medicare or Medicaid to an entity with which the physician (or an immediate family member) has a financial relationship, unless an exception applies. Designated health services include: clinical laboratory, physical therapy, occupational therapy, radiology, radiation therapy, DME, parenteral/enteral nutrients, prosthetics/orthotics, home health, outpatient prescription drugs, and inpatient/outpatient hospital services. Strict liability statute — no intent element required. If a financial relationship exists and no exception is met, the referral is prohibited and any resulting claim is a false claim. Penalties: denial of payment, refund obligation, civil monetary penalty up to $26,520 per service (2024), $177,558 for circumvention schemes, and exclusion from federal programs. Exceptions: in-office ancillary services, physician services, rental (FMV), employment, personal service arrangements, group practice, academic medical centers, and others.', '["Prohibition: physician may not refer DHS to entity with which physician has financial relationship","Financial relationship: ownership/investment interest or compensation arrangement","Designated Health Services (DHS): 11 categories including lab, PT, OT, radiology, DME, hospital services","Strict liability: no intent required — if relationship exists and no exception, referral prohibited","Claims for referred DHS are automatically false claims — no payment","Physician: includes MD, DO, DDS, DPM, DC, OD, optometrist","Immediate family member: spouse, children, siblings, parents, in-laws, grandparents, grandchildren","Exceptions: in-office ancillary services (same building, supervised, billed by referring physician)","Exception: bona fide employment relationships — FMV compensation","Exception: personal service arrangements — written agreement, FMV, commercially reasonable","Exception: rental of office space or equipment — written agreement, FMV, exclusive use","Exception: physician services — referral to another physician in same group practice","Exception: academic medical centers — specific criteria met","Penalties: denial of payment, refund, CMP up to $26,520 per service","Circumvention scheme: CMP up to $177,558","Exclusion from Medicare/Medicaid programs","Voluntary self-disclosure protocol: CMS accepts self-disclosures with reduced penalties"]', '[{"section":"1395nn(a)","description":"Prohibition on referrals — physician with financial relationship"},{"section":"1395nn(b)","description":"General exceptions — physician services, in-office ancillary, prepaid plans"},{"section":"1395nn(c)","description":"General exception — physician services within a group practice"},{"section":"1395nn(d)","description":"Additional exceptions — hospital ownership, rural providers"},{"section":"1395nn(e)","description":"Exceptions for ownership/investment — publicly traded, hospital in PR"},{"section":"1395nn(e)(2)-(8)","description":"Compensation exceptions — rental, employment, personal service, FMV"},{"section":"1395nn(g)","description":"Sanctions — denial of payment, refund, CMP, exclusion"},{"section":"1395nn(h)","description":"Definitions — DHS, financial relationship, group practice, referral"},{"section":"42 CFR 411.350-411.389","description":"Stark Law regulations — detailed exception requirements"}]', '["Stark_compliance_review","financial_relationship_disclosure","referral_pattern_analysis","FMV_appraisal","compensation_agreement","lease_agreement","group_practice_documentation","self_disclosure","CMP_notice","billing_records","ownership_disclosure","CMS_advisory_opinion"]', '["medical-billing-surgery-fraud-audit"]', 'CMS / HHS-OIG / DOJ / Federal Courts', 0, 1, datetime('now'), datetime('now'));

-- CPT / ICD-10 Coding Standards
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_089', 'ETHICARA', 'FEDERAL_STATUTE', 'US', 'HIPAA Administrative Simplification (42 USC § 1320d-2) — CPT (AMA) / ICD-10-CM (WHO/CMS) / HCPCS (CMS) Mandated Code Sets', 'HIPAA § 1320d-2 / CPT / ICD-10 / HCPCS', 'CPT, ICD-10, and HCPCS Coding Standards — HIPAA-Mandated Medical Code Sets', 'HIPAA Administrative Simplification requires the use of standard code sets for electronic healthcare transactions. The three primary mandated code sets are: (1) CPT (Current Procedural Terminology) — maintained by AMA — describes medical procedures and services; (2) ICD-10-CM (International Classification of Diseases, 10th Revision, Clinical Modification) — maintained by WHO/CMS/NCHS — describes diagnoses and conditions; (3) HCPCS (Healthcare Common Procedure Coding System) — maintained by CMS — includes Level I (CPT) and Level II (non-physician services, DME, supplies). Accurate coding is legally required. Upcoding (billing a higher-level code than justified), unbundling (billing separately for services that should be billed together), and miscoding are common fraud schemes prosecuted under the FCA, AKS, and state fraud statutes. NCCI (National Correct Coding Initiative) edits identify code pairs that should not be billed together. Medical necessity must support the code selected.', '["HIPAA mandates standard code sets for electronic transactions (45 CFR Part 162)","CPT: Current Procedural Terminology — AMA — procedures, services, 5-digit codes","ICD-10-CM: diagnoses and conditions — ~70,000 codes — mandatory since 10/1/2015","ICD-10-PCS: procedure codes for inpatient hospital — CMS","HCPCS Level II: non-physician services, DME, ambulance, supplies — CMS","Coding must accurately reflect services rendered and documented in medical record","Medical necessity: diagnosis code must support medical necessity of procedure code","Upcoding: billing higher-level code than documentation supports — fraud","Unbundling: billing component codes separately when comprehensive code exists — fraud","Miscoding: assigning incorrect diagnosis or procedure code — may be fraud if knowing","NCCI edits: CMS code pairs that should not be billed together — claims editing","Modifier usage: must comply with CPT/CMS guidelines for modifier application","E/M coding (99201-99215): evaluation and management — based on complexity/time","Documentation must support code level selected — medical record is the source of truth","Annual code updates: CPT (January), ICD-10 (October) — must use current codes","Compliance program: OIG recommends coding compliance program for all providers"]', '[{"section":"42 USC § 1320d-2","description":"HIPAA: standard code sets for electronic transactions"},{"section":"45 CFR Part 162","description":"HIPAA transaction and code set standards regulations"},{"section":"45 CFR 162.1000","description":"Medical data code sets — general requirements"},{"section":"45 CFR 162.1002","description":"Specified code sets: ICD-10-CM, CPT, HCPCS, CDT, NDC"},{"section":"CPT (AMA)","description":"Current Procedural Terminology — procedure and service codes"},{"section":"ICD-10-CM","description":"International Classification of Diseases — diagnosis codes"},{"section":"HCPCS Level II","description":"Non-physician services, DME, supplies — CMS maintained"},{"section":"NCCI","description":"National Correct Coding Initiative — code pair edits"},{"section":"OIG Compliance Guidance","description":"OIG recommended coding compliance programs for providers"}]', '["coding_audit","billing_records","medical_records","NCCI_edit_report","E_M_documentation","modifier_analysis","compliance_program","corrective_action_plan","overpayment_refund","FCA_complaint","OIG_audit_report","RAC_audit","coding_training_records"]', '["medical-billing-surgery-fraud-audit"]', 'CMS / HHS-OIG / DOJ / MAC (Medicare Administrative Contractors) / RACs', 0, 1, datetime('now'), datetime('now'));

-- No Surprises Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_090', 'ETHICARA', 'FEDERAL_STATUTE', 'US', 'Public Law 116-260 / 42 USC § 300gg-111 (No Surprises Act — Effective January 1, 2022)', '42 USC § 300gg-111 / No Surprises Act', 'No Surprises Act — Protection Against Surprise Medical Billing', 'The No Surprises Act (NSA), effective January 1, 2022, protects patients from surprise (balance) billing for emergency services, non-emergency services at in-network facilities by out-of-network providers, and air ambulance services by out-of-network providers. Patients pay only in-network cost-sharing amounts (deductible, copayment, coinsurance) even when treated by out-of-network providers in these situations. Providers and health plans must resolve payment disputes through an Independent Dispute Resolution (IDR) process. Good faith estimate requirement: uninsured/self-pay patients must receive an advance good faith estimate of expected charges. If actual charges exceed the estimate by $400 or more, patient may initiate a patient-provider dispute resolution process. Provider/facility must provide notice and consent (written) before balance billing an insured patient for non-emergency out-of-network services — without valid consent, balance billing is prohibited. State laws may provide additional protections (California AB 72 / Health & Safety Code § 1371.9).', '["Protects against surprise billing for: emergency services, OON at in-network facility, air ambulance","Patient pays only in-network cost-sharing: deductible, copay, coinsurance","Applies to group and individual health insurance (not Medicare, Medicaid, VA, TRICARE, IHS)","Emergency services: all services until patient can be safely transferred — regardless of network status","Non-emergency at in-network facility: ancillary services by OON provider (anesthesia, pathology, radiology, etc.)","Notice and consent: written consent required before OON balance billing for scheduled non-emergency","Notice must be provided 72 hours before service (or day of if less than 72 hours notice of appointment)","Independent Dispute Resolution (IDR): binding arbitration between provider and insurer","IDR: each party submits offer, arbitrator selects one — baseball-style arbitration","Qualifying Payment Amount (QPA): median contracted rate — key IDR consideration","Good faith estimate: uninsured/self-pay patients must receive before scheduled services","Patient-provider dispute resolution: if charges exceed estimate by $400+","Provider penalties: up to $10,000 per violation","State balance billing laws may provide additional protections","California AB 72 (HSC § 1371.9): state surprise billing protections (predates NSA)","Continuity of care: transitioning patients may continue with OON provider at in-network rates"]', '[{"section":"42 USC § 300gg-111","description":"Balance billing prohibition — emergency and non-emergency at in-network facility"},{"section":"42 USC § 300gg-112","description":"Air ambulance services — OON balance billing prohibited"},{"section":"42 USC § 300gg-131","description":"Notice and consent for OON non-emergency services"},{"section":"42 USC § 300gg-132","description":"Provider requirements — public disclosure, billing compliance"},{"section":"42 USC § 300gg-135","description":"Advanced Explanation of Benefits — insured patients"},{"section":"42 USC § 300gg-136","description":"Good faith estimate for uninsured/self-pay patients"},{"section":"42 USC § 300gg-137","description":"Patient-provider dispute resolution — estimate exceeded by $400+"},{"section":"42 USC § 300gg-111(c)","description":"Independent Dispute Resolution (IDR) process — provider vs. insurer"},{"section":"45 CFR Part 149","description":"NSA implementing regulations"},{"section":"HSC § 1371.9","description":"California AB 72 — state balance billing protections"}]', '["good_faith_estimate","notice_and_consent_form","EOB","IDR_petition","QPA_calculation","patient_dispute_resolution","balance_bill","provider_directory","NSA_compliance_attestation","surprise_billing_complaint","AB72_complaint"]', '["medical-billing-surgery-fraud-audit"]', 'CMS / HHS / State Insurance Departments / Federal and State Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- VIGILUS — Digital Forensics / Evidence
-- ═══════════════════════════════════════════════════════════════════════════

-- CalECPA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_036', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 1546-1546.4 (California Electronic Communications Privacy Act — CalECPA, SB 178)', 'PC §§ 1546-1546.4 / CalECPA', 'California Electronic Communications Privacy Act — Warrant Requirement for Electronic Communications', 'CalECPA (SB 178, effective January 1, 2016) requires a warrant, wiretap order, or other specified legal process before a government entity may compel the production of or access to electronic communication information or electronic device information from a service provider or by searching or seizing a device. Covers: emails, text messages, location data, IP addresses, browsing history, social media, cloud-stored data, and any information stored on electronic devices. Exceptions: emergency (imminent danger of death or serious injury), consent, lost/stolen device, device accessible to public, and border searches. Notification: individual must be notified contemporaneously with warrant execution, with limited delayed notification provisions. Suppression remedy: evidence obtained in violation is subject to exclusion. Service providers may voluntarily disclose only in limited emergency circumstances. Stronger than federal ECPA (18 USC § 2510+) — California provides broader digital privacy protections.', '["Warrant required before government access to electronic communications or device information","Electronic communication information: content, metadata, sender/recipient, date/time, location, IP addresses","Electronic device information: any information stored on or generated by a device — phones, computers, tablets","Service provider must not disclose to government without warrant/wiretap order/specified legal process","Warrant must describe with particularity information to be seized","Warrant must be executed within 10 days (PC § 1534)","Emergency exception: imminent danger of death or serious physical injury (§ 1546.1(c))","Consent exception: authorized by device owner/user (§ 1546.1(c)(4))","Delayed notification: court may authorize delay up to 90 days upon showing (§ 1546.2)","Suppression remedy: evidence obtained in violation subject to exclusion (§ 1546.4)","Service provider voluntary disclosure: only in emergency involving danger to life (§ 1546.1(d))","Annual transparency report: DOJ must publish statistics on CalECPA orders (§ 1546.3)","Stronger than federal ECPA: warrant required for all electronic information, not just content","Applies to all state and local government entities — law enforcement, administrative agencies"]', '[{"section":"1546(a)","description":"Definitions — electronic communication information, electronic device information"},{"section":"1546.1(a)","description":"Warrant required for government access to electronic information"},{"section":"1546.1(b)","description":"Specified legal process alternatives — wiretap order, subpoena with notice"},{"section":"1546.1(c)","description":"Exceptions — emergency, consent, accessible to public, lost/stolen device"},{"section":"1546.1(d)","description":"Service provider voluntary disclosure — emergency only"},{"section":"1546.2","description":"Notification requirement — contemporaneous, delayed notification provisions"},{"section":"1546.3","description":"DOJ annual transparency report on CalECPA orders"},{"section":"1546.4","description":"Remedies — suppression of evidence obtained in violation"}]', '["search_warrant","CalECPA_order","suppression_motion","service_provider_subpoena","emergency_disclosure_request","notification_of_search","delayed_notification_order","transparency_report","1983_complaint","motion_to_quash"]', '["identity-theft-fraud-audit"]', 'Superior Court (warrant issuance) / DOJ (transparency reporting)', 1, 1, datetime('now'), datetime('now'));

-- FRE 901/902 — Authentication of Digital Evidence
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_037', 'VIGILUS', 'FEDERAL_STATUTE', 'US', 'Federal Rules of Evidence 901-902 (Authentication and Identification of Evidence — Digital Evidence)', 'FRE 901-902', 'Federal Rules of Evidence — Authentication of Digital Evidence', 'FRE 901(a) requires that proponent produce evidence sufficient to support a finding that the item is what the proponent claims it is before it can be admitted. For digital evidence, authentication requires showing the evidence has not been altered and accurately represents what it purports to be. FRE 901(b) provides illustrative examples: testimony of a witness with knowledge (901(b)(1)), distinctive characteristics (901(b)(4) — email headers, metadata, writing style), process or system testimony showing it produces accurate results (901(b)(9) — forensic tools, hash values). FRE 902 provides for self-authentication of certain documents: certified records (902(4)), official publications (902(5)), and — critically — certified records of regularly conducted activity accompanied by declaration (902(11)/(12)). Lorraine v. Markel (2007) provides comprehensive framework for digital evidence admissibility under FRE: relevance, authenticity, hearsay, best evidence rule, and Rule 403 balancing. Hash values (MD5, SHA-256) are widely accepted to establish digital evidence integrity.', '["Authentication: evidence sufficient to support finding that item is what proponent claims (901(a))","Testimony of witness with knowledge: person who saw the creation, transmission, or receipt (901(b)(1))","Distinctive characteristics: email headers, metadata, IP addresses, writing style, context (901(b)(4))","Process or system: forensic imaging tools producing accurate results, hash verification (901(b)(9))","Reply doctrine: message is authenticated by content of reply to earlier authenticated communication","Hash values: MD5, SHA-256 hash comparison establishes integrity/non-alteration","Metadata: creation date, modification date, author, GPS coordinates — authenticating information","Chain of custody: documentation of who handled evidence from seizure to presentation","Self-authentication (902): certified business records with declaration (902(11)/(12))","Best evidence rule (FRE 1001-1008): original or duplicate — applies to digital documents","Lorraine v. Markel framework: relevance + authenticity + hearsay + original/duplicate + Rule 403","Social media: must authenticate authorship — circumstantial evidence acceptable","Screenshots: must show URL, date captured, preservation method","California Evidence Code § 1552: printout of computer information presumed accurate copy","Forensic imaging: bit-for-bit copy with write-blocker — industry standard authentication"]', '[{"section":"901(a)","description":"Authentication requirement — sufficient evidence to support finding"},{"section":"901(b)(1)","description":"Testimony of witness with knowledge"},{"section":"901(b)(4)","description":"Distinctive characteristics — appearance, contents, substance, internal patterns"},{"section":"901(b)(9)","description":"Process or system — evidence describing and showing accurate results"},{"section":"902(4)","description":"Self-authentication: certified copies of public records"},{"section":"902(11)","description":"Self-authentication: certified domestic records of regularly conducted activity"},{"section":"902(12)","description":"Self-authentication: certified foreign records of regularly conducted activity"},{"section":"Lorraine v. Markel (2007)","description":"Comprehensive framework for digital evidence admissibility"},{"section":"Evid Code § 1552","description":"California: computer printout presumed accurate — rebuttable"}]', '["forensic_image","hash_verification_report","chain_of_custody_log","authentication_declaration","metadata_report","screenshot_with_certification","expert_declaration","business_records_declaration_902(11)","forensic_examination_report","Lorraine_admissibility_brief"]', '["identity-theft-fraud-audit"]', 'Federal and State Courts', 0, 1, datetime('now'), datetime('now'));

-- Chain of Custody — NIST SP 800-86
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_038', 'VIGILUS', 'PROFESSIONAL_STANDARD', 'US', 'NIST Special Publication 800-86 (Guide to Integrating Forensic Techniques into Incident Response) + SWGDE Best Practices', 'NIST SP 800-86 / SWGDE', 'Chain of Custody Standards for Digital Evidence — NIST and SWGDE Forensic Guidelines', 'NIST SP 800-86 provides guidelines for integrating forensic techniques into incident response, including standards for digital evidence collection, examination, analysis, and reporting. The four-phase forensic process: (1) Collection — identifying, labeling, recording, and acquiring data while preserving integrity; (2) Examination — assessing and extracting relevant data using forensically sound methods; (3) Analysis — analyzing results using legally justifiable methods and techniques; (4) Reporting — documenting actions, methods, tools, and conclusions. Chain of custody requires continuous documentation of evidence handling from identification through court presentation: who, what, when, where, why, and how at each transfer. Scientific Working Group on Digital Evidence (SWGDE) standards complement NIST and are widely referenced in federal and state courts. Key principles: use of write-blockers during acquisition, forensic imaging (bit-for-bit copy), hash verification before and after examination, examination on forensic copy only (never original), contemporaneous documentation, validated forensic tools (EnCase, FTK, Autopsy, Cellebrite).', '["Four-phase forensic process: Collection → Examination → Analysis → Reporting","Collection: identify, label, record, and acquire data from possible sources","Use write-blockers to prevent modification of original evidence","Forensic imaging: create bit-for-bit copy of original media","Hash verification: compute and document hash before and after acquisition","Never examine original evidence — work only on forensic copy","Examination: process data through validated forensic tools","Analysis: correlate data from multiple sources, draw conclusions","Reporting: document methodology, tools, findings — reproducible results","Chain of custody documentation: continuous record of evidence handling","Each transfer documented: who received, from whom, when, where, condition","Evidence storage: secure location with access controls and environmental protections","Validated tools: EnCase, FTK (Forensic Toolkit), Autopsy, Cellebrite UFED, X-Ways","Tool validation: NIST CFTT (Computer Forensic Tool Testing) program","SWGDE standards: minimum requirements for forensic examination quality","Examiner qualifications: training, certification (EnCE, ACE, CFCE, GCFE)","Error rate: known or potential error rate of methodology — Daubert factor","Peer review: methodology subject to peer review — Daubert factor","Lab accreditation: ISO 17025 / ASCLD for forensic laboratories"]', '[{"section":"NIST SP 800-86 § 3","description":"Forensic process overview — collection, examination, analysis, reporting"},{"section":"NIST SP 800-86 § 4","description":"Data collection — sources, acquisition, chain of custody"},{"section":"NIST SP 800-86 § 5","description":"Examination and analysis — tools, techniques, methodology"},{"section":"NIST SP 800-86 § 6","description":"Using data from data files — file system forensics"},{"section":"NIST SP 800-86 § 7","description":"Using data from operating systems — OS artifacts"},{"section":"NIST SP 800-86 § 8","description":"Using data from network traffic — packet capture, logs"},{"section":"SWGDE Best Practices","description":"Digital evidence quality standards — collection, preservation, examination"},{"section":"NIST CFTT","description":"Computer Forensic Tool Testing — tool validation program"},{"section":"ISO 17025","description":"Laboratory accreditation for forensic testing"}]', '["chain_of_custody_form","forensic_image","hash_verification_log","evidence_intake_form","forensic_examination_report","write_blocker_verification","tool_validation_report","examiner_credentials","evidence_storage_log","analysis_report","SWGDE_compliance_checklist","expert_declaration"]', '["identity-theft-fraud-audit"]', 'NIST / SWGDE / Federal and State Courts (admissibility standards)', 0, 1, datetime('now'), datetime('now'));

-- PC § 502(e) — Civil Remedies for Computer Crime
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_039', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 502 (Comprehensive Computer Data Access and Fraud Act — Civil Remedies under § 502(e))', 'PC § 502(e)', 'California Computer Crime — Civil Remedies for Unauthorized Access and Data Theft', 'PC § 502 prohibits various forms of unauthorized computer access and data theft. Section 502(c) enumerates criminal offenses: knowingly accessing and without permission altering, damaging, deleting, destroying, or otherwise using any data, computer, computer system, or network to devise or execute a scheme to defraud, deceive, or extort, or wrongfully controlling or obtaining money, property, or data. Section 502(e) provides a private civil right of action: any person who suffers damage or loss by reason of a violation of § 502(c) may bring a civil action for compensatory damages, injunctive relief, and other equitable relief. Prevailing plaintiff may recover reasonable attorney fees. Owner or lessee of computer, system, data, or network may bring action. Applicable to: unauthorized access to email accounts, social media accounts, financial accounts, identity theft involving computer systems, SIM swap fraud, data destruction, spyware installation, and unauthorized monitoring of electronic communications. Complements federal CFAA (18 USC § 1030) which has a $5,000 damage threshold for civil action.', '["§ 502(c)(1): knowingly access and alter, damage, delete, destroy, or use data without permission","§ 502(c)(2): knowingly access to devise/execute scheme to defraud or extort","§ 502(c)(3): knowingly and without permission use or cause to be used computer services","§ 502(c)(4): knowingly access to wrongfully control or obtain money, property, or data","§ 502(c)(5): knowingly and without permission disrupt or cause disruption of computer services","§ 502(c)(6): knowingly and without permission provide or assist in unauthorized access","§ 502(c)(7): knowingly and without permission access computer, system, or network","Criminal penalties: misdemeanor or felony depending on conduct and prior offenses","§ 502(e)(1): civil action for compensatory damages and injunctive relief","§ 502(e)(2): prevailing plaintiff may recover reasonable attorney fees","Owner or lessee of computer, data, system, or network may bring civil action","No damage threshold for civil action (unlike federal CFAA $5,000 minimum)","Applicable to: unauthorized email access, social media hacking, SIM swap, spyware","Applicable to: identity theft via computer, data destruction, account takeover","Injunctive relief available: TRO and preliminary injunction to prevent ongoing access","§ 502(e)(3): if defendant acted with willful and malicious intent, treble damages available (pending legislation)","Complements federal CFAA (18 USC § 1030) — broader state protections, no damage threshold"]', '[{"section":"502(a)","description":"Legislative findings — protection of computer systems and data"},{"section":"502(b)","description":"Definitions — access, computer, data, network, system, damage, injury"},{"section":"502(c)(1)","description":"Criminal: unauthorized alteration, damage, deletion, destruction of data"},{"section":"502(c)(2)","description":"Criminal: unauthorized access to defraud, deceive, or extort"},{"section":"502(c)(3)","description":"Criminal: unauthorized use of computer services"},{"section":"502(c)(4)","description":"Criminal: unauthorized access to obtain money, property, or data"},{"section":"502(c)(5)","description":"Criminal: disruption of computer services"},{"section":"502(c)(7)","description":"Criminal: unauthorized access to computer, system, or network"},{"section":"502(e)(1)","description":"Civil action: compensatory damages and injunctive relief"},{"section":"502(e)(2)","description":"Attorney fees to prevailing plaintiff"},{"section":"18 USC § 1030","description":"Federal CFAA — complementary federal computer fraud statute"}]', '["civil_complaint_502","criminal_complaint","TRO_application","preliminary_injunction","forensic_examination_report","damage_calculation","attorney_fee_motion","declaration_of_unauthorized_access","IP_address_logs","account_access_records","SIM_swap_evidence","data_recovery_report"]', '["identity-theft-fraud-audit"]', 'District Attorney / Superior Court / Federal Court (CFAA)', 1, 1, datetime('now'), datetime('now'));
